/**
 *
 * @param {Chart} chartInstance
 * @constructor
 */
import { pick, defined, isArray } from '../../../utils/zcutils';
import { mathMin } from '../../zc-constants';
import { TIME_DATATYPE } from '../../datatype-constants';
import { getOrdinalRange } from '../../../axis/scale';
import { scale } from '../../main-zc-init';
import { DataProcessor as P } from '../../data-processor';
import { d3_map, d3_merge, d3_set } from '../../d3-constants';
import { PreProcessor } from '../pre-data-processor';

function HierarchicalDataAdapter(chartInstance) {
    this.chart = chartInstance;
    this.originalSeries = chartInstance.seriesdata;
    this.initialize();
}

HierarchicalDataAdapter.prototype = {
    initialize: function() {
        var layout = this;

        layout.hierarchyLayout = true;
        layout.dataCount = 0;
        layout.globalChartType = layout.originalSeries.type;
    },

    getCategories: function() {
        return this.categories;
    },

    getPivotLayout: function() {
        return this.pivotLayout;
    }
};

/* ********************************** Static Functions ****************************/

/**
 *
 * @param arr
 * @return {boolean}
 */

HierarchicalDataAdapter.is3D = function(arr) {
    return isArray(arr) && isArray(arr[0]);
};

/**
 *
 * @param series
 * @return {boolean|*}
 */

HierarchicalDataAdapter.isArrayOfSeries = function(series) {
    return HierarchicalDataAdapter.is3D(series.data) && defined(series.seriesname);
};

/**
 *
 * @param arr
 * @return {{}}
 */

HierarchicalDataAdapter.keysObject = function(arr) {
    var t = {};
    if (arr && arr.length) {
        arr.forEach(function(el) {
            t[el.value] = el;
        });
    }
    return t;
};

P.HierarchicalDataAdapter = HierarchicalDataAdapter;
